  enabled: boolean;
  quietHoursStart?: string; // ISO 8601 time, e.g. "22:00"
  quietHoursEnd?: string;
}

interface UserNotificationPreferences {
  userId: UserId;
  globalOptOut: boolean; // nuclear switch вҖ” nothing gets through
  channels: Record<Channel, ChannelPreference>;
  categoryOptOuts: NotificationCategory[]; // user-level category muting
  updatedAt: Date;
}

// в”Җв”Җ Contact Data в”Җв”Җ

interface UserContactData {
  userId: UserId;
  email?: { address: string; verified: boolean; bounceCount: number };
  phone?: { number: string; verified: boolean; bounceCount: number };
  pushTokens: PushToken[];
}

interface PushToken {
  token: string;
  platform: "apns" | "fcm";
  registeredAt: Date;
  lastSuccessAt?: Date;
}

// в”Җв”Җ Consent Ledger (append-only) в”Җв”Җ

interface ConsentEvent {
  userId: UserId;
  channel: Channel;
  action: "opt_in" | "opt_out";
  source: "user_settings" | "unsubscribe_link" | "admin_override";
  timestamp: Date;
  ipAddress?: string;
  evidence?: string; // e.g. double-opt-in token
}

// в”Җв”Җ Notification в”Җв”Җ

interface Notification {
  id: NotificationId;
  idempotencyKey: IdempotencyKey;
  recipientId: UserId;
  category: NotificationCategory;
  channels: Channel[]; // requested channels; preference filter narrows
  payload: NotificationPayload;
  createdAt: Date;
  expiresAt?: Date; // TTL вҖ” stale notifications are not retried
}

interface NotificationPayload {
  title: string;
  body: string;
  templateId?: string;
  templateVars?: Record<string, string>;
  actionUrl?: string;
}

// в”Җв”Җ Delivery Record (outbox) в”Җв”Җ

enum DeliveryStatus {
  PENDING = "pending",
  SENT = "sent",
  DELIVERED = "delivered",
  FAILED = "failed",
  BOUNCED = "bounced",
  RATE_LIMITED = "rate_limited",
  FILTERED = "filtered", // preference/consent gate rejected it
}

interface DeliveryRecord {
  notificationId: NotificationId;
  channel: Channel;
  status: DeliveryStatus;
  attempts: number;
  lastAttemptAt?: Date;
  nextRetryAt?: Date;
  providerMessageId?: string;
  failureReason?: string;
}

// в”Җв”Җ Rate Limit в”Җв”Җ

interface RateLimitConfig {
  channel: Channel;
  category: NotificationCategory;
  windowSeconds: number;
  maxPerWindow: number;
}

interface RateLimitState {
  userId: UserId;
  channel: Channel;
  category: NotificationCategory;
  windowStart: Date;
  count: number;
}
```

